CREATE TABLE "bd_usuarios" (
  "usuario_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "usuario_nom" varchar(35) NOT NULL,
  "usuario_ape" varchar(35) NOT NULL,
  "usuario_idn" varchar(10) UNIQUE NOT NULL,
  "usuario_cor" varchar(50) NOT NULL,
  "usuario_tel" char(15) NOT NULL,
  "usuario_psh" varchar(20) NOT NULL,
  "usuario_rol" int NOT NULL
);

CREATE TABLE "bd_funciona" (
  "funciona_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "funciona_us" int UNIQUE NOT NULL,
  "funciona_ra" int NOT NULL,
  "funciona_ni" varchar(20) NOT NULL,
  "funciona_un" int NOT NULL
);

CREATE TABLE "bd_infracto" (
  "infract_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "infract_pas" varchar(50),
  "persona_frk" int NOT NULL
);

CREATE TABLE "bd_unidadep" (
  "unidade_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "unidade_nom" varchar(50) NOT NULL
);

CREATE TABLE "bd_vehiculo" (
  "vehicul_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "vehicul_pla" varchar(50) UNIQUE NOT NULL,
  "vehicul_mrc" varchar(50) NOT NULL,
  "vehicul_mod" varchar(50) NOT NULL,
  "vehicul_col" varchar(30) NOT NULL,
  "vehicul_ano" int(4) NOT NULL,
  "vehicul_due" int NOT NULL,
  "vehicul_tip" int NOT NULL
);

CREATE TABLE "bd_articulo" (
  "articul_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "articul_num" varchar(3) NOT NULL,
  "articul_nrl" varchar(4) NOT NULL,
  "articul_des" text NOT NULL,
  "articul_val" decimal(10,2) NOT NULL
);

CREATE TABLE "bd_multacab" (
  "multaca_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "multaca_nro" varchar(6) UNIQUE NOT NULL,
  "multaca_fec" date NOT NULL,
  "multaca_hor" time NOT NULL,
  "multaca_lug" varchar(250) NOT NULL,
  "multaca_fun" int NOT NULL,
  "multaca_ifr" int NOT NULL,
  "multaca_veh" int NOT NULL,
  "multaca_tip" int NOT NULL,
  "multaca_mon" decimal(10,2) NOT NULL,
  "multaca_est" varchar NOT NULL,
  "multaca_obs" text
);

CREATE TABLE "bd_multa_de" (
  "multa_de_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "multa_de_mu" int NOT NULL,
  "multa_de_ar" int NOT NULL,
  "multa_de_mo" decimal(10,2) NOT NULL
);

CREATE TABLE "bd_role_usu" (
  "role_usu_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "role_nombre" varchar NOT NULL,
  "role_descri" varchar NOT NULL
);

CREATE TABLE "bd_categori" (
  "catego_prik" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "catego_nomb" varchar NOT NULL,
  "catego_desc" varchar NOT NULL
);

CREATE TABLE "bd_multacat" (
  "multacat_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "mlct_mul_fk" int NOT NULL,
  "mlct_cat_fk" int NOT NULL
);

CREATE TABLE "bd_rango_fu" (
  "rango_fu_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "rango_nombr" varchar(30) UNIQUE NOT NULL,
  "rango_descr" varchar(100) NOT NULL
);

CREATE TABLE "bd_tipo_veh" (
  "tipo_veh_pk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "tipo_veh_no" varchar(20) UNIQUE NOT NULL
);

CREATE TABLE "bd_tipomult" (
  "tipmult_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "tipmult_nom" varchar(20) UNIQUE NOT NULL,
  "tipmult_des" varchar(100)
);

CREATE TABLE "bd_personas" (
  "persona_prk" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "persona_idn" varchar(12) UNIQUE NOT NULL,
  "persona_nom" varchar(50) NOT NULL,
  "persona_ape" varchar(50) NOT NULL,
  "persona_nac" varchar(2) NOT NULL,
  "persona_dir" varchar(150) NOT NULL,
  "persona_tel" varchar(15),
  "persona_cor" varchar(100)
);

ALTER TABLE "bd_multacab" ADD FOREIGN KEY ("multaca_tip") REFERENCES "bd_tipomult" ("tipmult_prk");

ALTER TABLE "bd_multacat" ADD FOREIGN KEY ("mlct_cat_fk") REFERENCES "bd_categori" ("catego_prik");

ALTER TABLE "bd_multacat" ADD FOREIGN KEY ("mlct_mul_fk") REFERENCES "bd_multacab" ("multaca_prk");

ALTER TABLE "bd_funciona" ADD FOREIGN KEY ("funciona_us") REFERENCES "bd_usuarios" ("usuario_prk");

ALTER TABLE "bd_funciona" ADD FOREIGN KEY ("funciona_un") REFERENCES "bd_unidadep" ("unidade_prk");

ALTER TABLE "bd_multacab" ADD FOREIGN KEY ("multaca_fun") REFERENCES "bd_funciona" ("funciona_pk");

ALTER TABLE "bd_multacab" ADD FOREIGN KEY ("multaca_ifr") REFERENCES "bd_infracto" ("infract_prk");

ALTER TABLE "bd_multacab" ADD FOREIGN KEY ("multaca_veh") REFERENCES "bd_vehiculo" ("vehicul_prk");

ALTER TABLE "bd_multa_de" ADD FOREIGN KEY ("multa_de_mu") REFERENCES "bd_multacab" ("multaca_prk");

ALTER TABLE "bd_multa_de" ADD FOREIGN KEY ("multa_de_ar") REFERENCES "bd_articulo" ("articul_prk");

ALTER TABLE "bd_funciona" ADD FOREIGN KEY ("funciona_ra") REFERENCES "bd_rango_fu" ("rango_fu_pk");

ALTER TABLE "bd_usuarios" ADD FOREIGN KEY ("usuario_rol") REFERENCES "bd_role_usu" ("role_usu_pk");

ALTER TABLE "bd_tipo_veh" ADD FOREIGN KEY ("tipo_veh_pk") REFERENCES "bd_vehiculo" ("vehicul_tip");

ALTER TABLE "bd_infracto" ADD FOREIGN KEY ("persona_frk") REFERENCES "bd_personas" ("persona_prk");

ALTER TABLE "bd_vehiculo" ADD FOREIGN KEY ("vehicul_due") REFERENCES "bd_personas" ("persona_prk");

